if (connectionName) {
    connection = ec.entity.find("moqui.device.DeviceConnection").condition("connectionName", connectionName).one()
} else {
    connection = ec.entity.find("moqui.device.DeviceConnection").condition("deviceId", deviceId).one()
}
if (!connection) throw new IllegalArgumentException("Connection not found for device: ${deviceId}")

String ctiPath = connection.transportConfig
if (!ctiPath) throw new IllegalArgumentException("Connection transportConfig must specify driver path.")

String serialNumber = device.serialNumber
if (connection.options) {
    Map optsMap = [:]
    connection.options.split(",")*.trim().each {
        def parts = it.split("=")
        if (parts.length == 2) optsMap.put(parts[0], parts[1])
    }
    if (optsMap.serial) serialNumber = optsMap.serial
}
if (!serialNumber) serialNumber = connection.connectionName

// get JEP tool factory
final JepToolFactory tool = ec.getTool("Jep", JepToolFactory.class)
Map<String, Object> pyResults = [:]

try (Interpreter interpreter = tool.getInterpreter()) {
    URL scriptUrl = ec.resource.getLocationReference("component://moqui-genicam/script").getUrl()
    String scriptDir = ""
    if (scriptUrl != null) {
        try {
