if (pyResults) {
    tensorId = pyResults.get("tensorId")
    tensorContentId = pyResults.get("tensorContentId")
    contentLocation = pyResults.get("contentLocation")
}

import org.moqui.context.ExecutionContext
import org.moqui.entity.EntityValue
import org.moqui.entity.EntityCondition
import java.sql.Timestamp
import java.io.File

ExecutionContext ec = context.ec

long keepMillis = daysToKeep * 24 * 60 * 60 * 1000L
Timestamp thresholdDate = new Timestamp(System.currentTimeMillis() - keepMillis)

ec.logger.info("Cleaning up GenICam ToF tensors older than ${thresholdDate} (daysToKeep=${daysToKeep})...")

// Find TensorContent older than threshold
List<EntityValue> oldContents = ec.entity.find("moqui.math.TensorContent")
    .condition("contentDate", EntityCondition.LESS_THAN, thresholdDate)
    .condition("contentTypeEnumId", "TCntNpy")
    .list()

int deletedCount = 0
for (EntityValue content in oldContents) {
    String filePath = content.contentLocation
    if (filePath) {
        File file = new File(filePath)
        if (file.exists()) {
            try {
                file.delete()
                ec.logger.info("Deleted old tensor file: ${filePath}")
            } catch (Exception e) {
                ec.logger.error("Failed to delete tensor file ${filePath}: ${e.getMessage()}")
            }
        }
    }

    String tensorId = content.tensorId

    // Perform DB deletions programmatically in a transaction to maintain integrity
    boolean beganTx = ec.transaction.begin(null)
    try {
        // Delete TensorContent
        content.delete()

        // Delete TensorAxis
        ec.entity.find("moqui.math.TensorAxis").condition("tensorId", tensorId).deleteAll()

        // Delete Tensor
        ec.entity.find("moqui.math.Tensor").condition("tensorId", tensorId).deleteAll()

        ec.transaction.commit(beganTx)
        deletedCount++
    } catch (Throwable t) {
        ec.transaction.rollback(beganTx, "Failed to clean tensor DB records", t)
        ec.logger.error("Failed to delete DB records for tensor ${tensorId}: ${t.getMessage()}")
    }
}

ec.logger.info("Successfully cleaned up ${deletedCount} old ToF tensors.")
